import numpy as np

def is_hermitian(A: np.ndarray, tol: float = 1e-10) -> bool:
    """Check if A = A†."""
    return np.allclose(A, A.conj().T, atol=tol)

def is_unitary(U: np.ndarray, tol: float = 1e-10) -> bool:
    """Check if U†U = I."""
    n = U.shape[0]
    return np.allclose(U.conj().T @ U, np.eye(n), atol=tol)

def is_projector(P: np.ndarray, tol: float = 1e-10) -> bool:
    """Check if P² = P and P = P†."""
    idempotent = np.allclose(P @ P, P, atol=tol)
    hermitian = np.allclose(P, P.conj().T, atol=tol)
    return idempotent and hermitian

def is_normal(A: np.ndarray, tol: float = 1e-10) -> bool:
    """Check if AA† = A†A."""
    return np.allclose(A @ A.conj().T, A.conj().T @ A, atol=tol)

def classify_operator(A: np.ndarray) -> list:
    """Return list of all properties the operator has."""
    props = []
    if is_hermitian(A):
        props.append('Hermitian')
    if is_unitary(A):
        props.append('Unitary')
    if is_projector(A):
        props.append('Projector')
    if is_normal(A):
        props.append('Normal')
    return props

# Test with various operators
X = np.array([[0, 1], [1, 0]], dtype=complex)
H = np.array([[1, 1], [1, -1]], dtype=complex) / np.sqrt(2)
S = np.array([[1, 0], [0, 1j]])
P0 = np.array([[1, 0], [0, 0]], dtype=complex)
A = np.array([[1, 1], [0, 1]], dtype=complex)

print("Operator Classification:")
for name, op in [('X', X), ('H', H), ('S', S), ('P₀', P0), ('A', A)]:
    props = classify_operator(op)
    print(f"  {name}: {props}")

# Additional analysis
print("\nDetailed analysis:")
for name, op in [('X', X), ('H', H), ('S', S), ('P₀', P0)]:
    eigenvalues = np.linalg.eigvals(op)
    print(f"\n{name}:")
    print(f"  Eigenvalues: {np.round(eigenvalues, 4)}")
    if is_hermitian(op):
        print(f"  All real: {np.allclose(eigenvalues.imag, 0)}")
    if is_unitary(op):
        print(f"  All |λ|=1: {np.allclose(np.abs(eigenvalues), 1)}")
